    function isJqueryReady(auszufuehrendeFunction){
		var isJquery = typeof jQuery;
		if(isJquery !== "undefined"){
			auszufuehrendeFunction();
			return isJquery;
		}else{
			var interv = setInterval(function(){
				if(isJquery !== "undefined"){
					clearInterval(interv);
					auszufuehrendeFunction();
					return isJquery;
				}
			}, 200);
		}
	}

